// filepath: c:\Users\USER\Desktop\Software Programming\GodemarsEmpire2\src\App.js
import React from "react";

function App() {
  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gradient-to-br from-blue-100 to-purple-200">
      <h1 className="text-4xl font-bold text-purple-700 mb-4">
        Welcome to Godemars Empire
      </h1>
      <p className="text-lg text-gray-700">
        Explore technology, innovation, and creativity!
      </p>
      <button className="mt-8 px-6 py-2 bg-purple-600 text-white rounded shadow hover:bg-purple-700 transition">
        Get Started
      </button>
    </div>
  );
}

export default App;
